    private void jFirstNameActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_jFirstNameActionPerformed
        // TODO add your handling code here:
        // Allow the user to enter their first name
        if (jFirstName.getText().equals("")){
            JOptionPane.showMessageDialog(null, "Please enter your first name");
        }
        else {
            JOptionPane.showMessageDialog(null, "Your first name is " + jFirstName.getText());
        }
    }//GEN-LAST:event_jFirstNameActionPerformed

    private void jPhoneNumberActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_jPhoneNumberActionPerformed
        // TODO add your handling code here:
        
        // Define the regex for the phone number pattern.
            String regex = "^\\+\\d{1,3}\\d{1,10}$";

        // The user must input the phone number in the JTextField.
            String phoneNumber = jPhoneNumber.getText();

        // Compile the pattern.
            Pattern pattern = Pattern.compile(regex);

        // Create a matcher for the phone number.
            Matcher matcher = pattern.matcher(phoneNumber);

        // Check if the phoneNumber fully matches the regex.
            if (matcher.matches()) {
        // Code to execute if the phone number is valid.
            JOptionPane.showMessageDialog(null, "Cellphone number successfully added");
}           else {
        // Code to execute if the phone number is invalid.
            JOptionPane.showMessageDialog(null, "Cellphone number incorrectly formatted or does not contain international code");
            }
    }                                            

