    private void jUsernameActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_jUsernameActionPerformed
        // TODO add your handling code here:
        // Determine wheater the username contains("_") and lenght is atleast 5 charecters
        if (jUsername.getText().contains("_") && jUsername.getText().length() ==5){
            // if it contains the required it must be a success
            JOptionPane.showMessageDialog(null,"Username successfully captured");
}
        else{
            //If it does not meet the minimum requirements it must display an error message
            JOptionPane.showMessageDialog(null, "Username is not correctly formatted, please ensure that your username"
                    + " contains an underscore and is no more than five charecters in length."); 
        }
    }//GEN-LAST:event_jUsernameActionPerformed

