    private void PasswordActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_PasswordActionPerformed
        // TODO add your handling code here:
        //Prompt the user to enter their password
                if (Password.getText().length() >= 8 
                        && Password.getText().matches(".*[A-Z].*") 
                        && Password.getText().matches(".*[0-9].*")
                        && Password.getText().matches(".*[!@#$%].*")) {
                     // if it contains the required it must be a success
            JOptionPane.showMessageDialog(null,"Password successfully captured");
}
        else{
                    //If it does not meet the minimum requirements it must display an error message
                JOptionPane.showMessageDialog(null, "Password is not correctly formatted; please ensure that "
             + "the password cointains at least eight charecters, a capital letter,"
             + " a number, and a special charecter.");
             }
    }//GEN-LAST:event_PasswordActionPerformed

    private void jSignUpActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_jSignUpActionPerformed
        // TODO add your handling code here:
        //If the username is correctly formatted & password is what is required and phoneNumber contains the country code the username account must be created.6
        if (jUsername.getText().contains("_") && jUsername.getText().length() <=5 && (Password.getText().length() >= 8 
                     && Password.getText().matches(".*[A-Z].*") 
                     && Password.getText().matches(".*[0-9].*")
                     && Password.getText().matches(".*[!@#$%].*")
                     && jPhoneNumber.getText().matches("^\\+\\d{1,3}[ -]?\\d{10}$")))
        { 
        Login LoginFrame = new Login();
        LoginFrame.setVisible(true);
        LoginFrame.pack();
        LoginFrame.setLocationRelativeTo(null);
        this.dispose();
        }
        else {
            //If Username,Password adn phone number are incorrectly formatted display this messsage
            JOptionPane.showMessageDialog(null, "Username or password incorrect please try again.");

        }
    }//GEN-LAST:event_jSignUpActionPerformed

    
    
